async function updateUser(req, res) {
  const targetUserId = parseInt(req.params.id, 10);

  if (req.user.id !== targetUserId && req.user.role !== 'admin') {
    return res.status(403).json({ error: 'Cannot modify other users' });
  }

  const updates = req.body;
  const allowedFields = ['name', 'email', 'department', 'role', 'notification_preferences'];

  const setClauses = [];
  const values = [];
  let paramIndex = 1;

  for (const [key, value] of Object.entries(updates)) {
    if (allowedFields.includes(key)) {
      setClauses.push(`${key} = $${paramIndex++}`);
      values.push(typeof value === 'object' ? JSON.stringify(value) : value);
    }
  }

  if (setClauses.length === 0) {
    return res.status(400).json({ error: 'No valid fields to update' });
  }

  values.push(targetUserId);

  try {
    const result = await db.query(
      `UPDATE users SET ${setClauses.join(', ')} WHERE id = $${paramIndex} RETURNING id, email, name, role, department`,
      values
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'User not found' });
    }

    res.json(result.rows[0]);
  } catch (err) {
    console.error('User update error:', err);
    res.status(500).json({ error: 'Failed to update user' });
  }
}

async function createUser(req, res) {
  const { email, password, name, role, department } = req.body;

  if (!email || !password || !name) {
    return res.status(400).json({ error: 'Email, password, and name required' });
  }

  const validRoles = ['viewer', 'operator', 'manager', 'admin'];
  const userRole = validRoles.includes(role) ? role : 'viewer';

  try {
    const passwordHash = await bcrypt.hash(password, 12);

    const result = await db.query(
      'INSERT INTO users (email, password_hash, name, role, department) VALUES ($1, $2, $3, $4, $5) RETURNING id, email, name, role, department',
      [email, passwordHash, name, userRole, department]
    );

    res.status(201).json(result.rows[0]);
  } catch (err) {
    if (err.code === '23505') {
      return res.status(409).json({ error: 'Email already exists' });
    }
    console.error('User creation error:', err);
    res.status(500).json({ error: 'Failed to create user' });
  }
}

async function changePassword(req, res) {
  const targetUserId = parseInt(req.params.id, 10);
  const { currentPassword, newPassword } = req.body;

  if (req.user.id !== targetUserId) {
    return res.status(403).json({ error: 'Cannot change other users\' passwords' });
  }

  if (!currentPassword || !newPassword) {
    return res.status(400).json({ error: 'Current and new passwords required' });
  }

  if (newPassword.length < 8) {
    return res.status(400).json({ error: 'Password must be at least 8 characters' });
  }

  try {
    const result = await db.query(
      'SELECT password_hash FROM users WHERE id = $1',
      [targetUserId]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'User not found' });
    }

    const valid = await bcrypt.compare(currentPassword, result.rows[0].password_hash);
    if (!valid) {
      return res.status(401).json({ error: 'Current password is incorrect' });
    }

    const newHash = await bcrypt.hash(newPassword, 12);
    await db.query('UPDATE users SET password_hash = $1 WHERE id = $2', [newHash, targetUserId]);

    res.json({ message: 'Password updated successfully' });
  } catch (err) {
    console.error('Password change error:', err);
    res.status(500).json({ error: 'Failed to change password' });
  }
}

async function registerWebhook(req, res) {
  const { name, url, events } = req.body;

  if (!name || !url || !events) {
    return res.status(400).json({ error: 'Name, URL, and events required' });
  }

  if (!Array.isArray(events) || events.length === 0) {
    return res.status(400).json({ error: 'At least one event type required' });
  }

  const webhookSecret = crypto.randomBytes(32).toString('hex');

  try {
    const result = await db.query(
      'INSERT INTO webhooks (user_id, name, url, events, secret) VALUES ($1, $2, $3, $4, $5) RETURNING id, name, url, events',
      [req.user.id, name, url, JSON.stringify(events), webhookSecret]
    );

    res.status(201).json({
      ...result.rows[0],
      secret: webhookSecret,
      message: 'Store the secret securely for signature verification.',
    });
  } catch (err) {
    console.error('Webhook creation error:', err);
    res.status(500).json({ error: 'Failed to create webhook' });
  }
}

async function testWebhook(req, res) {
  try {
    const result = await db.query(
      'SELECT id, url, secret FROM webhooks WHERE id = $1 AND user_id = $2',
      [req.params.id, req.user.id]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Webhook not found' });
    }

    const webhook = result.rows[0];
    const testPayload = {
      event: 'test',
      timestamp: new Date().toISOString(),
      data: { message: 'This is a test webhook delivery' },
    };

    const signature = crypto
      .createHmac('sha256', webhook.secret)
      .update(JSON.stringify(testPayload))
      .digest('hex');

    const response = await fetch(webhook.url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Webhook-Signature': signature,
      },
      body: JSON.stringify(testPayload),
      timeout: 10000,
    });

    res.json({
      delivered: true,
      statusCode: response.status,
      message: 'Test webhook sent successfully',
    });
  } catch (err) {
    console.error('Webhook test error:', err);
    res.json({
      delivered: false,
      error: err.message,
      message: 'Failed to deliver test webhook',
    });
  }
}

async function sendNotification(req, res) {
  const { url, payload } = req.body;

  if (!url || !payload) {
    return res.status(400).json({ error: 'URL and payload required' });
  }

  try {
    const parsedUrl = new URL(url);
    const isDomainAllowed = ALLOWED_WEBHOOK_DOMAINS.some(
      domain => parsedUrl.hostname === domain
    );

    if (!isDomainAllowed) {
      return res.status(403).json({ error: 'Domain not in allowlist' });
    }

    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      timeout: 5000,
    });

    res.json({
      delivered: response.ok,
      statusCode: response.status,
    });
  } catch (err) {
    console.error('Notification error:', err);
    res.status(500).json({ error: 'Failed to send notification' });
  }
}
